css:
.loader {
  position: relative;
  width: 120px;
  height: 170px;
  background: #ffffff;
  padding-top: 22px;
  border-radius: 25px;
  box-shadow: 5px 5px 0 #666666;
  display: flex;
  flex-direction: column;
  align-items: center;
}
.clock {
  width: 74px;
  height: 74px;
  border: 6px solid #111111;
  border-radius: 50%;
  position: relative;
  background: #f6f6f6;
  box-shadow: inset 0 0 0 4px #ffffff;
}
.clock::before { content: ""; position: absolute; inset: 33px; background: #111; border-radius: 50%; }
.clock span { position: absolute; left: 35px; top: 14px; width: 4px; height: 25px; background: #111; transform-origin: 50% 100%; animation: clockHand 6s linear infinite; }
.clock span:nth-child(2) { height: 20px; top: 20px; animation-duration: 1.5s; }
.stage { width: 72px; height: 7px; margin-top: 10px; background: #111111; border-radius: 15px; box-shadow: 2px 2px 0 #666666; }
.hold { width: 3px; height: 56px; background: #32cd32; transform-origin: top center; animation: dangle 1.3s ease-in-out infinite; box-shadow: 4px 4px 0 #666666; }
.ball { width: 38px; height: 38px; border-radius: 50%; background: #171717; transform: translate(-17px, 48px); box-shadow: 1px 1px 0 #666666; }
@keyframes dangle { 0%,100% { transform: rotate(42deg); } 50% { transform: rotate(-42deg); } }
@keyframes clockHand { to { transform: rotate(360deg); } }
